int n,x,y,ans[maxn];

int main(){

	cin>>n>>x>>y;

	for(int i=1;i<=n;i++)

		for(int j=1;j<i;j++)

		{

			int dist1=i-j;

			int dist2=abs(x-j)+abs(y-i)+1;

			int dist=min(dist1,dist2);

			ans[dist]++;

		}

	for(int i=1;i<=n-1;i++)cout<<ans[i]<<endl;

	return 0;

}
